THOUGHT: The miscompile stems from InstCombine folding a select-of-fcmps into an fabs compare while propagating 'ninf' FMF to the synthesized fabs. This makes fabs poison on -inf even when the original select would yield a benign false, increasing poison. The safe fix is to avoid carrying 'ninf' to the created fabs in foldSelectWithFCmpToFabs. I'll add a small helper in that function to create fabs with FMF sanitized to clear no-infs, using IRBuilder's FastMathFlagsGuard to restore flags, and update all fabs creations in that function to use it.

```bash
applypatch << 'PATCH'
*** Begin Patch
*** Update File: llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@
 static Instruction *foldSelectWithFCmpToFabs(SelectInst &SI,
                                              InstCombinerImpl &IC) {
+  // When creating a synthesized fabs() while folding select-of-fcmp patterns,
+  // be careful with FastMathFlags propagation: 'ninf' coming from just one arm
+  // of the select can make the new fabs poison for -inf even if the original
+  // select would have produced a non-poison value. To avoid increasing poison,
+  // clear 'no-infs' on the created fabs.
+  auto CreateSafeFabs = [&](Value *X) -> Value * {
+    IRBuilderBase::FastMathFlagsGuard Guard(IC.Builder);
+    FastMathFlags FMF = SI.getFastMathFlags();
+    // Do not propagate 'no-infs' to the synthesized fabs.
+    FMF.setNoInfs(false);
+    IC.Builder.setFastMathFlags(FMF);
+    return IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
+  };
@@
-        Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
+        Value *Fabs = CreateSafeFabs(X);
         return IC.replaceInstUsesWith(SI, Fabs);
@@
-        Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
+        Value *Fabs = CreateSafeFabs(X);
         return IC.replaceInstUsesWith(SI, Fabs);
@@
-      Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
+      Value *Fabs = CreateSafeFabs(X);
       return IC.replaceInstUsesWith(SI, Fabs);
@@
-      Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
+      Value *Fabs = CreateSafeFabs(X);
       Instruction *NewFNeg = UnaryOperator::CreateFNeg(Fabs);
@@
-    Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
+    Value *Fabs = CreateSafeFabs(X);
     if (!IsNeg ^ Swap)
       return IC.replaceInstUsesWith(SI, Fabs);
*** End Patch
PATCH
```

