messages.content:
THOUGHT: The transform foldSelectWithFCmpToFabs in InstCombineSelect.cpp synthesizes fabs calls and currently inherits FastMathFlags including 'no-infs' from the select. That can make the new fabs poison on -inf, increasing poison compared to the original select. To fix, I'll add a local CreateSafeFabs helper inside this function that clears 'no-infs' before creating the fabs and replace all fabs creations within this function to use it. Then I'll submit the patch.

```bash
awk '
  BEGIN{infunc=0; inserted=0}
  /static Instruction *foldSelectWithFCmpToFabs\(SelectInst &SI,/ {infunc=1}
  {print}
  infunc && !inserted && /\{/ {
    print "  // When creating a synthesized fabs() while folding select-of-fcmp patterns,";
    print "  // be careful with FastMathFlags propagation: '\''ninf'\'' coming from just one arm";
    print "  // of the select can make the new fabs poison for -inf even if the original";
    print "  // select would have produced a non-poison value. To avoid increasing poison,";
    print "  // clear '\''no-infs'\'' on the created fabs.";
    print "  auto CreateSafeFabs = [&](Value *X) -> Value * {";
    print "    IRBuilderBase::FastMathFlagsGuard Guard(IC.Builder);";
    print "    FastMathFlags FMF = SI.getFastMathFlags();";
    print "    // Do not propagate '\''no-infs'\'' to the synthesized fabs.";
    print "    FMF.setNoInfs(false);";
    print "    IC.Builder.setFastMathFlags(FMF);";
    print "    return IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);";
    print "  };";
    inserted=1
  }
  infunc && /CreateUnaryIntrinsic\(Intrinsic::fabs, X, &SI\)/ {
    sub(/IC\.Builder\.CreateUnaryIntrinsic\(Intrinsic::fabs, X, &SI\)/,"CreateSafeFabs(X)")
  }
  /};/ && infunc {infunc=0}
' llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp > /tmp/InstCombineSelect.cpp.tmp && \
mv /tmp/InstCombineSelect.cpp.tmp llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp && submit-patch
```

