THOUGHT: The created helper currently contains literal "\n" sequences and doesn't explicitly set FastMathFlags on the fabs call. I will rewrite the CreateSafeFabs block cleanly to clear no-infs and set the sanitized FMF on the CallInst, then show the updated section to verify.

```bash
awk '
  BEGIN{rewrite=0}
  /auto CreateSafeFabs = \[\&\]\(Value \*X\) -> Value \* \{/ {print "  auto CreateSafeFabs = [&](Value *X) -> Value * {"; rewrite=1; next}
  rewrite==1 {
    if ($0 ~ /\};/) {
      print "    IRBuilderBase::FastMathFlagsGuard Guard(IC.Builder);"
      print "    FastMathFlags FMF = SI.getFastMathFlags();"
      print "    // Do not propagate '\''no-infs'\'' to the synthesized fabs."
      print "    FMF.setNoInfs(false);"
      print "    CallInst *F = cast<CallInst>(IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI));"
      print "    F->setFastMathFlags(FMF);"
      print "    return F;"
      print "  };"
      rewrite=2
      next
    } else {
      next
    }
  }
  {print}
' llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp > /tmp/ic_sel.cpp && mv /tmp/ic_sel.cpp llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp && nl -ba llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp | sed -n '2818,2832p'
```

